import * as React from "react";
import Layout from "../components/Layout";
import { graphql, Link as GatsbyLink } from "gatsby";
import { Box, BaseStyles, Heading, Link, Flex, Text } from "theme-ui";
import DetailNav from "../components/DetailNav";
import { groupByTime, getDateString } from "../utils";
import { Anchor } from "../components/Icons";
import FooterNav from "../components/FooterNav";
import SEO from "../components/seo";
import DetailTitle from "../components/DetailTitle";

// markup
const IndexPage = ({ data, location, pageContext }) => {
  const items = data.allAwesomeItem.nodes;
  const type = pageContext.type || "day";
  const groups = groupByTime(items, type);
  const awesomeListMeta = data.awesomeListMeta;
  const readmeParsedAt = awesomeListMeta.readmeParsedAt;

  let previousInfo = null;
  if (data.previous) {
    previousInfo = {
      name: data.previous.repo,
      url:
        type === "week" || type === "homeWeek"
          ? `/${data.previous.repo}/week/`
          : `/${data.previous.repo}/`,
    };
  }
  let nextInfo = null;
  if (data.next) {
    nextInfo = {
      name: data.next.repo,
      url:
        type === "week" || type === "homeWeek"
          ? `/${data.next.repo}/week/`
          : `/${data.next.repo}/`,
    };
  }
  let title =
    type === "week" || type === "homeWeek"
      ? `Track ${pageContext.repo} Updates Weekly`
      : `Track ${pageContext.repo} Updates Daily`;
  let description = data.awesomeList.description;
  return (
    <Layout location={location} repo={pageContext.repo}>
      <SEO title={title} description={description} article />

      <Box p="default" sx={{ maxWidth: "5xl" }}>
        <DetailTitle meta={data.awesomeList}></DetailTitle>
        <DetailNav meta={data.awesomeList} location={location}></DetailNav>
        <Box pt="default">
          {groups.map((group, index) => {
            return (
              <Box key={`grouped-by-time-${group.id}`}>
                <Heading as="h2" variant="anchor" pb="default">
                  <Link
                    variant="anchor"
                    id={`${group.id}`}
                    href={`#${group.id}`}
                  >
                    <Anchor></Anchor>
                  </Link>
                  <Text>{getDateString(group.updatedAt, type)}</Text>
                </Heading>
                <Box variant="docs.date">
                  <BaseStyles>
                    <div
                      dangerouslySetInnerHTML={{
                        __html: group.itemsHTML,
                      }}
                    ></div>
                  </BaseStyles>
                </Box>
              </Box>
            );
          })}
          <Flex sx={{ justifyContent: "flex-end" }}>
            <Box>
              Last Checked At: <Text color="textMuted">{readmeParsedAt}</Text>
            </Box>
          </Flex>
          <FooterNav previous={previousInfo} next={nextInfo}></FooterNav>
        </Box>
      </Box>
    </Layout>
  );
};

export default IndexPage;
export const pageQuery = graphql`
  query awesomeList(
    $id: String!
    $previousId: String
    $nextId: String
    $repo: String!
  ) {
    site {
      siteMetadata {
        title
      }
    }
    awesomeList(id: { eq: $id }) {
      repo
      descriptionHTML
      description
      stargazerCount
      repoUpdatedTime
    }
    awesomeListMeta(repo: { eq: $repo }) {
      readmeParsedAt
    }
    allAwesomeItem(
      filter: { awesomeListRepo: { eq: $repo } }
      sort: { fields: updateTime, order: DESC }
    ) {
      nodes {
        categoryHTML
        itemHTML
        updatedAt
      }
    }
    previous: awesomeList(id: { eq: $previousId }) {
      id
      repo
    }
    next: awesomeList(id: { eq: $nextId }) {
      id
      repo
    }
  }
`;
